mapper.select:
SELECT cafeno, name, namesub, cnt, rdate, seqno, visible
FROM cafe
where cafeno=#{cafeno}

mapper.update:
UPDATE cafe
SET name=#{name}, namesub=#{namesub}, cnt=#{cnt}, rdate=sysdate, seqno=#{seqno}, visible=#{visible}
WHERE cafeno=#{cafeno}

UPDATE cafe
SET seqno=seqno-1
WHERE cafeno=#{cafeno}

UPDATE cafe
SET seqno=seqno+1
WHERE cafeno=#{cafeno}
